// Extract messaging event from Meta webhook payload
const body = $input.first().json.body;
const entry = body?.entry?.[0];
const messaging = entry?.messaging?.[0];

if (!messaging) return [{ json: { skip: true, reason: 'no_messaging_event' } }];
if (messaging.delivery || messaging.read) return [{ json: { skip: true, reason: 'delivery_or_read_event' } }];
if (messaging.message?.is_echo) return [{ json: { skip: true, reason: 'echo_message' } }];
if (!messaging.message?.text) return [{ json: { skip: true, reason: 'no_text_message' } }];

return [{ json: { skip: false, senderPsid: messaging.sender.id, messageText: messaging.message.text, timestamp: messaging.timestamp } }];

// HYBRID ROUTER: Checks message against static rules FIRST to save AI cost.
// Only falls through to AI if no confident answer can be given from rules/sheets.

const msg = $input.first().json.messageText;
const psid = $input.first().json.senderPsid;
const normalized = msg.toLowerCase().trim().replace(/[^a-z0-9\s]/g, '');
const words = normalized.split(/\s+/);

// --- BRANCH 1: Static Direct Replies (NO AI COST) ---
const greetings = ['hi','hello','hey','hola','assalamualaikum','salam','yo','sup'];
const thanks = ['thanks','thank','thankyou','thx','jazakallah','shukria'];
const byes = ['bye','goodbye','see ya','later','seeya','cya'];

if (words.length <= 3) {
  if (words.some(w => greetings.includes(w))) {
    return [{ json: { route: 'greeting', senderPsid: psid, replyText: 'Hello! Welcome to our store. I can help you find products, answer questions, or place an order. What are you looking for today?' } }];
  }
  if (words.some(w => thanks.includes(w))) {
    return [{ json: { route: 'thanks', senderPsid: psid, replyText: 'You are welcome! Let me know if there is anything else I can help with.' } }];
  }
  if (words.some(w => byes.includes(w))) {
    return [{ json: { route: 'bye', senderPsid: psid, replyText: 'Goodbye! Thanks for chatting with us. Come back anytime!' } }];
  }
}

// --- BRANCH 6: Human Support Detection (NO AI COST) ---
const supportWords = ['human','agent','person','representative','manager','speak to','talk to','complaint','refund','fraud','overcharged','legal','lawyer'];
const angryPatterns = normalized === normalized.toUpperCase() && msg.length > 10;
if (supportWords.some(w => normalized.includes(w)) || angryPatterns) {
  return [{ json: { route: 'support', senderPsid: psid, messageText: msg } }];
}

// --- BRANCH 5: Order Tracking Detection (NO AI COST) ---
const trackWords = ['track','tracking','where is my order','order status','delivery status','has it shipped','my order','when will it arrive'];
const orderIdMatch = msg.match(/ORD-[\w-]+/i);
if (trackWords.some(w => normalized.includes(w)) || orderIdMatch) {
  return [{ json: { route: 'tracking', senderPsid: psid, messageText: msg, orderId: orderIdMatch ? orderIdMatch[0].toUpperCase() : null } }];
}

// --- BRANCH 4: Order/Buy Intent Detection ---
const buyWords = ['buy','order','purchase','i want','ill take','add to cart','i need','id like'];
if (buyWords.some(w => normalized.includes(w))) {
  return [{ json: { route: 'order_intent', senderPsid: psid, messageText: msg } }];
}

// --- Remaining: FAQ or Product or AI Fallback ---
// Pass forward for sheet-based checks
return [{ json: { route: 'check_sheets', senderPsid: psid, messageText: msg, normalized: normalized } }];

// FAQ + PRODUCT SEARCH (NO AI COST)
// Tries FAQ first, then products. Only falls to AI if neither matches.

const routerData = $('Needs Sheet Lookup?').first().json;
const customerMsg = routerData.messageText;
const normalized = routerData.normalized;
const psid = routerData.senderPsid;
const words = normalized.split(/\s+/).filter(w => w.length > 2).filter(w => !['the','and','for','are','this','that','with','have','show','want','your','what','does','come','any','can','you','please','hello','much','how','there'].includes(w));

// --- TRY FAQ FIRST ---
const faqRows = $('Read FAQ Sheet').all().map(i => i.json);
const activeFaqs = faqRows.filter(f => String(f.Active).toUpperCase() === 'YES');

let bestFaq = null;
let bestFaqScore = 0;

for (const faq of activeFaqs) {
  const faqKeywords = (faq.Keywords || '').toLowerCase().split(',').map(k => k.trim());
  const questionWords = (faq.Question || '').toLowerCase().split(/\s+/);
  let score = 0;
  for (const word of words) {
    if (faqKeywords.some(k => k.includes(word) || word.includes(k))) score += 2;
    if (questionWords.includes(word)) score += 1;
  }
  if (score > bestFaqScore) {
    bestFaqScore = score;
    bestFaq = faq;
  }
}

// Strong FAQ match threshold: at least 3 points
if (bestFaq && bestFaqScore >= 3) {
  return [{ json: { route: 'faq_match', senderPsid: psid, replyText: bestFaq.Answer, faqId: bestFaq.FAQ_ID, aiUsed: false } }];
}

// --- TRY PRODUCTS ---
const productRows = $('Read Products Sheet').all().map(i => i.json);
const activeProducts = productRows.filter(p => String(p.Active).toUpperCase() === 'YES');

const scored = activeProducts.map(product => {
  const searchable = [product.Product_Name||'', product.Category||'', product.Description||'', product.Size||'', product.Color||'', product.Search_Keywords||''].join(' ').toLowerCase();
  let score = 0;
  for (const term of words) { if (searchable.includes(term)) score++; }
  return { ...product, score };
}).filter(p => p.score > 0);

// Group by Product_ID
const grouped = {};
for (const m of scored) {
  const pid = m.Product_ID;
  if (!grouped[pid]) { grouped[pid] = { Product_ID: pid, Product_Name: m.Product_Name, Price: m.Price, Currency: m.Currency||'USD', sizes: [], colors: [], inStock: 0, topScore: 0 }; }
  if (m.score > grouped[pid].topScore) grouped[pid].topScore = m.score;
  if (String(m.In_Stock).toUpperCase() === 'YES') {
    grouped[pid].inStock++;
    if (m.Size && !grouped[pid].sizes.includes(m.Size)) grouped[pid].sizes.push(m.Size);
    if (m.Color && !grouped[pid].colors.includes(m.Color)) grouped[pid].colors.push(m.Color);
  }
}

const results = Object.values(grouped).sort((a,b) => b.topScore - a.topScore).slice(0, 5);

if (results.length > 0) {
  let reply = `I found ${results.length} product${results.length>1?'s':''} for you:\n\n`;
  results.forEach((p, i) => {
    reply += `${i+1}. ${p.Product_Name} — $${p.Price}\n`;
    if (p.sizes.length) reply += `   Sizes: ${p.sizes.join(', ')}\n`;
    if (p.colors.length) reply += `   Colors: ${p.colors.join(', ')}\n`;
    if (p.inStock === 0) reply += `   (Currently out of stock)\n`;
    reply += '\n';
  });
  reply += 'Would you like to order any of these? Just tell me the product, size, and color!';
  return [{ json: { route: 'product_match', senderPsid: psid, replyText: reply, matchCount: results.length, aiUsed: false } }];
}

// --- NO MATCH: Fall through to AI Agent ---
if (words.length === 0) {
  return [{ json: { route: 'ai_fallback', senderPsid: psid, messageText: customerMsg, replyText: "I'd love to help! You can ask me about our products, shipping, returns, sizing, or place an order. What would you like to know?", aiUsed: false } }];
}

return [{ json: { route: 'ai_fallback', senderPsid: psid, messageText: customerMsg, aiUsed: true } }];

// Prepare final reply text for Messenger Send API
// Handles all routes: greeting, thanks, bye, faq, product, tracking, support, ai

const data = $input.first().json;
let psid = data.senderPsid || '';
let replyText = data.replyText || data.output || data.text || '';

// If coming from AI Agent, extract the output
if (!replyText && data.response) {
  replyText = data.response;
}
if (!replyText) {
  replyText = 'I apologize, I could not process your request. Please try again or type "speak to a human" for support.';
}

// Truncate to Messenger 2000 char limit
if (replyText.length > 1950) {
  replyText = replyText.substring(0, 1947) + '...';
}

return [{ json: { senderPsid: psid, replyText: replyText } }];

// TRACKING LOOKUP (NO AI COST)
// Search Tracking tab by Order_ID or customer email
const data = $input.first().json;
const psid = data.senderPsid;
const orderId = data.orderId;
const msg = data.messageText;

// For v2, reply with instructions since we don't have tracking data connected yet
let reply = '';
if (orderId) {
  reply = `I found your order reference: ${orderId}\n\nLet me check the status for you. Our team will update you shortly with tracking details.\n\nIf you need immediate help, type "speak to a human".`;
} else {
  reply = 'I can help you track your order! Please provide your order number (it looks like ORD-YYYYMMDD-XXX).\n\nExample: "Track ORD-20250120-001"';
}

return [{ json: { route: 'tracking', senderPsid: psid, replyText: reply, aiUsed: false } }];

// SUPPORT TICKET HANDLER (NO AI COST)
const data = $input.first().json;
const psid = data.senderPsid;
const msg = data.messageText || '';

const reply = `I understand you need help from our team. I have flagged your conversation for priority support.\n\nOur team will respond to you in this chat within 2-4 hours (business hours: Mon-Fri, 9 AM - 6 PM).\n\nIf urgent, you can also email: support@yourbrand.com\n\nIs there anything else I can help with while you wait?`;

return [{ json: { route: 'support', senderPsid: psid, replyText: reply, aiUsed: false } }];

// ORDER INTENT HANDLER
const data = $input.first().json;
const psid = data.senderPsid;
const msg = data.messageText || '';

const reply = `Great, I would love to help you place an order!

To create your order, I need:
1. Which product? (e.g., Classic Black T-Shirt)
2. What size?
3. What color?
4. Your name and email
5. Shipping address

Which product are you interested in? You can also say "show me t-shirts" to browse first.`;

return [{ json: { route: 'order_intent', senderPsid: psid, replyText: reply, aiUsed: false } }];
